document.addEventListener('DOMContentLoaded', function () { const heroSlider = document.querySelector('.hero-slider'); if (heroSlider) { const slides = document.querySelectorAll('.hero-slide'); const dots = document.querySelectorAll('.slider-dot'); const prevBtn = document.querySelector('.slider-prev'); const nextBtn = document.querySelector('.slider-next'); let currentSlide = 0; let slideInterval; function showSlide(index) { if (index < 0) { currentSlide = slides.length - 1; } else if (index >= slides.length) { currentSlide = 0; } else { currentSlide = index; } slides.forEach(slide => { slide.classList.remove('active'); }); dots.forEach(dot => { dot.classList.remove('active'); }); slides[currentSlide].classList.add('active'); if (dots[currentSlide]) { dots[currentSlide].classList.add('active'); } } function nextSlide() { showSlide(currentSlide + 1); } function prevSlide() { showSlide(currentSlide - 1); } function startAutoSlide() { slideInterval = setInterval(nextSlide, 5000); } function stopAutoSlide() { clearInterval(slideInterval); } if (prevBtn) { prevBtn.addEventListener('click', () => { prevSlide(); stopAutoSlide(); startAutoSlide(); }); } if (nextBtn) { nextBtn.addEventListener('click', () => { nextSlide(); stopAutoSlide(); startAutoSlide(); }); } dots.forEach((dot, index) => { dot.addEventListener('click', () => { showSlide(index); stopAutoSlide(); startAutoSlide(); }); }); heroSlider.addEventListener('mouseenter', stopAutoSlide); heroSlider.addEventListener('mouseleave', startAutoSlide); let touchStartX = 0; let touchEndX = 0; heroSlider.addEventListener('touchstart', (e) => { touchStartX = e.changedTouches[0].screenX; stopAutoSlide(); }); heroSlider.addEventListener('touchend', (e) => { touchEndX = e.changedTouches[0].screenX; handleSwipe(); startAutoSlide(); }); function handleSwipe() { if (touchEndX < touchStartX - 50) { nextSlide(); } if (touchEndX > touchStartX + 50) { prevSlide(); } } document.addEventListener('keydown', (e) => { if (e.key === 'ArrowLeft') { prevSlide(); stopAutoSlide(); startAutoSlide(); } else if (e.key === 'ArrowRight') { nextSlide(); stopAutoSlide(); startAutoSlide(); } }); if (slides.length > 1) { startAutoSlide(); } } const navToggle = document.getElementById('navToggle'); const navMenu = document.getElementById('navMenu'); if (navToggle && navMenu) { navToggle.addEventListener('click', function (e) { e.stopPropagation(); const isExpanded = navMenu.classList.toggle('active'); navToggle.classList.toggle('active'); navToggle.setAttribute('aria-expanded', isExpanded ? 'true' : 'false'); }); document.addEventListener('click', function (e) { if (navMenu.classList.contains('active') && !navMenu.contains(e.target) && !navToggle.contains(e.target)) { navMenu.classList.remove('active'); navToggle.classList.remove('active'); navToggle.setAttribute('aria-expanded', 'false'); } }); } document.querySelectorAll('a[href^="#"]').forEach(anchor => { anchor.addEventListener('click', function (e) { const href = this.getAttribute('href'); if (href !== '#' && href.length > 1) { e.preventDefault(); const target = document.querySelector(href); if (target) { if (navMenu && navMenu.classList.contains('active')) { navMenu.classList.remove('active'); if (navToggle) { navToggle.classList.remove('active'); navToggle.setAttribute('aria-expanded', 'false'); } } requestAnimationFrame(() => { const offset = 80; const targetPosition = target.getBoundingClientRect().top + window.pageYOffset - offset; window.scrollTo({ top: targetPosition, behavior: 'smooth' }); }); } } }); }); const filterButtons = document.querySelectorAll('.filter-btn'); if (filterButtons.length > 0) { filterButtons.forEach(button => { button.addEventListener('click', function () { filterButtons.forEach(btn => btn.classList.remove('active')); this.classList.add('active'); const category = this.getAttribute('data-category'); const blogCards = document.querySelectorAll('.blog-card'); const cardsToShow = []; const cardsToHide = []; blogCards.forEach(card => { if (category === 'all' || card.getAttribute('data-category') === category) { cardsToShow.push(card); } else { cardsToHide.push(card); } }); requestAnimationFrame(() => { cardsToShow.forEach(card => { card.style.display = 'block'; requestAnimationFrame(() => { card.style.opacity = '1'; card.style.transform = 'scale(1)'; }); }); cardsToHide.forEach(card => { card.style.opacity = '0'; card.style.transform = 'scale(0.95)'; setTimeout(() => { card.style.display = 'none'; }, 300); }); }); }); }); } const observerOptions = { threshold: 0.1, rootMargin: '0px 0px -50px 0px' }; const observer = new IntersectionObserver(function (entries) { entries.forEach(entry => { if (entry.isIntersecting) { entry.target.style.opacity = '1'; entry.target.style.transform = 'translateY(0)'; } }); }, observerOptions); document.querySelectorAll('.service-card, .blog-card, .contact-item').forEach(el => { el.style.opacity = '0'; el.style.transform = 'translateY(30px)'; el.style.transition = 'opacity 0.6s ease, transform 0.6s ease'; observer.observe(el); }); const contactForm = document.querySelector('#appointmentForm'); if (contactForm) { contactForm.addEventListener('submit', async function (e) { e.preventDefault(); const form = this; const submitBtn = form.querySelector('#submitBtn'); const btnText = submitBtn.querySelector('.btn-text'); const btnLoading = submitBtn.querySelector('.btn-loading'); const formMessage = document.getElementById('form-message'); submitBtn.disabled = true; if (btnText) btnText.style.display = 'none'; if (btnLoading) btnLoading.style.display = 'inline'; const formData = new FormData(form); try { const response = await fetch(form.action, { method: 'POST', body: formData }); if (!response.ok) { throw new Error('HTTP hatası: ' + response.status); } const contentType = response.headers.get('content-type'); if (!contentType || !contentType.includes('application/json')) { const text = await response.text(); console.error('JSON olmayan yanıt:', text); throw new Error('Geçersiz yanıt formatı'); } const result = await response.json(); if (formMessage) { formMessage.style.display = 'block'; if (result.success) { formMessage.style.background = '#d1fae5'; formMessage.style.color = '#065f46'; formMessage.style.border = '1px solid #10b981'; formMessage.textContent = result.message; form.reset(); setTimeout(() => { if (formMessage) formMessage.style.display = 'none'; }, 5000); } else { formMessage.style.background = '#fee2e2'; formMessage.style.color = '#991b1b'; formMessage.style.border = '1px solid #ef4444'; formMessage.textContent = result.message || 'Bir hata oluştu. Lütfen tekrar deneyin.'; } } } catch (error) { console.error('Form gönderim hatası:', error); if (formMessage) { formMessage.style.display = 'block'; formMessage.style.background = '#fee2e2'; formMessage.style.color = '#991b1b'; formMessage.style.border = '1px solid #ef4444'; formMessage.textContent = 'Bir hata oluştu. Lütfen daha sonra tekrar deneyin.'; } } finally { submitBtn.disabled = false; if (btnText) btnText.style.display = 'inline'; if (btnLoading) btnLoading.style.display = 'none'; } }); } const showAllCertificatesBtn = document.getElementById('showAllCertificates'); if (showAllCertificatesBtn) { showAllCertificatesBtn.addEventListener('click', function () { const hiddenCertificates = document.querySelectorAll('.hidden-certificate'); hiddenCertificates.forEach(cert => { cert.style.display = 'block'; const img = cert.querySelector('img'); if (img && img.dataset.src) { img.src = img.dataset.src; } }); this.style.display = 'none'; document.getElementById('sertifikalar').scrollIntoView({ behavior: 'smooth', block: 'nearest' }); }); } }); document.querySelectorAll('.faq-question').forEach(button => { button.addEventListener('click', () => { const faqItem = button.parentElement; const isActive = faqItem.classList.contains('active'); document.querySelectorAll('.faq-item').forEach(item => { item.classList.remove('active'); const answer = item.querySelector('.faq-answer'); if (answer) answer.style.maxHeight = null; }); if (!isActive) { faqItem.classList.add('active'); const answer = faqItem.querySelector('.faq-answer'); if (answer) answer.style.maxHeight = answer.scrollHeight + 'px'; } }); });